const keyOf = ([x, y]: Cell): string => `${x},${y}`;
const parseKey = (key: string): Cell => key.split(",").map(Number) as Cell;

function countNeighbors(cells: Cell[]): Map<string, number> {
  const counts = new Map<string, number>();
  for (const [x, y] of cells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const key = keyOf([x + dx, y + dy]);
      counts.set(key, (counts.get(key) ?? 0) + 1);
    }
  }
  return counts;
}

function survives(isAlive: boolean, neighborCount: number): boolean {
  return neighborCount === 3 || (isAlive && neighborCount === 2);
}

export function nextGeneration(cells: Cell[]): Cell[] {
  const alive = new Set(cells.map(keyOf));
  const counts = countNeighbors(cells);
  return [...counts]
    .filter(([key, count]) => survives(alive.has(key), count))
    .map(([key]) => parseKey(key));
}

